from collections import defaultdict

class Solution(object):
    def interactionCosts(self, n, edges, group):
        G = max(group) + 1
        adj = defaultdict(list)
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        total_cnt = [0] * G
        for g in group:
            total_cnt[g] += 1
        # Post-order DFS to compute subtree group counts
        parent = [-1] * n
        order = []
        visited = [False] * n
        visited[0] = True
        stack = [0]
        while stack:
            u = stack.pop()
            order.append(u)
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    stack.append(v)
        # subtree_cnt[u][g] = count of group g in subtree of u
        subtree_cnt = [[0] * G for _ in range(n)]
        ans = 0
        for u in reversed(order):
            subtree_cnt[u][group[u]] += 1
            for v in adj[u]:
                if v != parent[u]:
                    for g in range(G):
                        subtree_cnt[u][g] += subtree_cnt[v][g]
            if parent[u] != -1:
                for g in range(G):
                    sc = subtree_cnt[u][g]
                    ans += sc * (total_cnt[g] - sc)
        return ans
